#include<bits/stdc++.h>
using namespace std;
long long a[10010],c[2010][2010];
const long long mod=1e9+7;
int main()
{
    long long n,m;
    scanf("%lld%lld",&n,&m);
    c[0][0]=1;
    for(long long i=1;i<=2000;i++)
    {
        c[i][0]=1;
        for(long long j=1;j<=i;j++)
        {
            c[i][j]=(c[i-1][j]+c[i-1][j-1])%mod;
        }
    }
    for(long long i=1;i<=m;i++)
    {
        scanf("%lld",&a[i]);
    }
    long long ans=0;
    for(long long i=1;i<=n;i++)
    {
        long long sum=c[n][i-1];
        for(long long j=1;j<=m;j++)
        {
            sum*=c[a[j]+n-i][n-i];
            sum%=mod;
        }
        if(i%2==1)
        {
            ans+=sum;
        }
        else
        {
            ans-=sum;
        }
        ans%=mod;
    }
    printf("%lld",(ans%mod+mod)%mod);
    return 0;
}
